    // In-memory store for demo purposes; replace with actual database/repository
    private static readonly Dictionary<string, Patient> PatientStore = new Dictionary<string, Patient>();
    private static readonly Dictionary<string, List<MedicalRecord>> MedicalRecordStore = new Dictionary<string, List<MedicalRecord>>();
    private static readonly List<AuditInfo> AuditLog = new List<AuditInfo>();
    private static readonly object LockObj = new object();

    static HealthcareRecordsService()
