    public HealthRecordResponse GetPatientRecords(HealthRecordRequest request)
    {
        ValidateRequest(request);

        var auditEntry = CreateAuditEntry("GetPatientRecords", request.RequestingUserId,
            request.RequestingOrganization, request.PurposeOfUse, request.PatientId);

        try
        {
            if (!PatientStore.ContainsKey(request.PatientId))
            {
                auditEntry.OutcomeCode = "PatientNotFound";
                LogAudit(auditEntry);

                throw new FaultException<HealthcareFault>(
                    new HealthcareFault
                    {
                        ErrorCode = "PATIENT_NOT_FOUND",
                        ErrorMessage = $"Patient with ID '{request.PatientId}' was not found.",
                        Timestamp = DateTime.UtcNow
                    },
                    new FaultReason("Patient not found"));
            }

            var patient = PatientStore[request.PatientId];
            var records = new List<MedicalRecord>();

            if (MedicalRecordStore.ContainsKey(request.PatientId))
            {
                records = MedicalRecordStore[request.PatientId];

                // Apply date range filter
                if (request.DateRangeStart.HasValue)
                    records = records.FindAll(r => r.EncounterDate >= request.DateRangeStart.Value);
                if (request.DateRangeEnd.HasValue)
                    records = records.FindAll(r => r.EncounterDate <= request.DateRangeEnd.Value);

                // Filter by record types if specified
                if (request.RecordTypes != null && request.RecordTypes.Count > 0)
                {
                    records = FilterRecordsByType(records, request.RecordTypes);
                }
            }

            auditEntry.OutcomeCode = "Success";
            LogAudit(auditEntry);

            return new HealthRecordResponse
            {
                ResponseId = Guid.NewGuid().ToString(),
                RequestId = request.RequestId,
                Success = true,
                StatusCode = "OK",
                StatusMessage = $"Found {records.Count} record(s) for patient.",
                Patient = MaskSensitivePatientData(patient, request.PurposeOfUse),
                MedicalRecords = records,
                ResponseTimestamp = DateTime.UtcNow,
                AuditInfo = auditEntry
            };
        }
        catch (FaultException)
        {
            throw;
        }
        catch (Exception ex)
        {
            auditEntry.OutcomeCode = "Error";
            LogAudit(auditEntry);

            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "INTERNAL_ERROR",
                    ErrorMessage = "An internal error occurred while processing the request.",
                    Details = ex.Message,
                    Timestamp = DateTime.UtcNow
                },
                new FaultReason("Internal server error"));
        }
    }

    public SubmitRecordResponse SubmitMedicalRecord(SubmitRecordRequest request)
    {
        if (request == null)
            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "INVALID_REQUEST",
                    ErrorMessage = "Request cannot be null.",
                    Timestamp = DateTime.UtcNow
                },
                new FaultReason("Invalid request"));

        if (request.Patient == null || string.IsNullOrEmpty(request.Patient.PatientId))
            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "INVALID_PATIENT",
                    ErrorMessage = "Patient information is required.",
                    Timestamp = DateTime.UtcNow
                },
                new FaultReason("Invalid patient data"));

        var auditEntry = CreateAuditEntry("SubmitMedicalRecord", request.SubmittingUserId,
            request.SubmittingOrganization, "Treatment", request.Patient.PatientId);

        try
        {
            lock (LockObj)
            {
                // Upsert patient
                PatientStore[request.Patient.PatientId] = request.Patient;

                // Assign record ID if not set
                if (request.MedicalRecord != null)
                {
                    if (string.IsNullOrEmpty(request.MedicalRecord.RecordId))
                        request.MedicalRecord.RecordId = Guid.NewGuid().ToString();

                    request.MedicalRecord.PatientId = request.Patient.PatientId;

                    if (!MedicalRecordStore.ContainsKey(request.Patient.PatientId))
                        MedicalRecordStore[request.Patient.PatientId] = new List<MedicalRecord>();

                    MedicalRecordStore[request.Patient.PatientId].Add(request.MedicalRecord);
                }
            }

            auditEntry.OutcomeCode = "Success";
            LogAudit(auditEntry);

            return new SubmitRecordResponse
            {
                ResponseId = Guid.NewGuid().ToString(),
                RequestId = request.RequestId,
                Success = true,
                StatusCode = "CREATED",
                StatusMessage = "Medical record submitted successfully.",
                AssignedRecordId = request.MedicalRecord?.RecordId,
                ResponseTimestamp = DateTime.UtcNow,
                AuditInfo = auditEntry
            };
        }
        catch (Exception ex)
        {
            auditEntry.OutcomeCode = "Error";
            LogAudit(auditEntry);

            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "SUBMISSION_FAILED",
                    ErrorMessage = "Failed to submit medical record.",
                    Details = ex.Message,
                    Timestamp = DateTime.UtcNow
                },
                new FaultReason("Submission failed"));
        }
    }

