    public List<Medication> GetActiveMedications(string patientId)
    {
        if (string.IsNullOrEmpty(patientId))
            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "INVALID_PATIENT_ID",
                    ErrorMessage = "Patient ID is required.",
                    Timestamp = DateTime.UtcNow
                },
                new FaultReason("Invalid patient ID"));

        var auditEntry = CreateAuditEntry("GetActiveMedications", "system",
            "Internal", "Treatment", patientId);

        var medications = new List<Medication>();

        if (MedicalRecordStore.ContainsKey(patientId))
        {
            foreach (var record in MedicalRecordStore[patientId])
            {
                if (record.Medications != null)
                {
                    medications.AddRange(
                        record.Medications.FindAll(m => !m.EndDate.HasValue || m.EndDate.Value > DateTime.UtcNow));
                }
            }
        }

        auditEntry.OutcomeCode = "Success";
        LogAudit(auditEntry);

        return medications;
    }

    public List<LabResult> GetLabResults(string patientId, DateTime? fromDate, DateTime? toDate)
    {
        if (string.IsNullOrEmpty(patientId))
            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "INVALID_PATIENT_ID",
                    ErrorMessage = "Patient ID is required.",
                    Timestamp = DateTime.UtcNow
                },
                new FaultReason("Invalid patient ID"));

        var auditEntry = CreateAuditEntry("GetLabResults", "system",
            "Internal", "Treatment", patientId);

        var labResults = new List<LabResult>();

        if (MedicalRecordStore.ContainsKey(patientId))
        {
            foreach (var record in MedicalRecordStore[patientId])
            {
                if (record.LabResults != null)
                {
                    var filtered = record.LabResults;
                    if (fromDate.HasValue)
                        filtered = filtered.FindAll(l => l.ResultDate >= fromDate.Value);
                    if (toDate.HasValue)
                        filtered = filtered.FindAll(l => l.ResultDate <= toDate.Value);

                    labResults.AddRange(filtered);
                }
            }
        }

        auditEntry.OutcomeCode = "Success";
        LogAudit(auditEntry);

        return labResults;
    }

    // ==================== Private Helper Methods ====================

    private void ValidateRequest(HealthRecordRequest request)
    {
        if (request == null)
            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "INVALID_REQUEST",
                    ErrorMessage = "Request cannot be null.",
                    Timestamp = DateTime.UtcNow
                },
                new FaultReason("Invalid request"));

        if (string.IsNullOrEmpty(request.PatientId))
            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "MISSING_PATIENT_ID",
                    ErrorMessage = "Patient ID is required.",
                    Timestamp = DateTime.UtcNow
                },
                new FaultReason("Missing patient ID"));

        if (string.IsNullOrEmpty(request.RequestingUserId))
            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "MISSING_USER_ID",
                    ErrorMessage = "Requesting user ID is required for HIPAA compliance.",
                    Timestamp = DateTime.UtcNow
                },
                new FaultReason("Missing user identification"));

        if (string.IsNullOrEmpty(request.PurposeOfUse))
            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "MISSING_PURPOSE",
                    ErrorMessage = "Purpose of use is required for HIPAA compliance.",
                    Timestamp = DateTime.UtcNow
                },
                new FaultReason("Missing purpose of use"));

        var validPurposes = new List<string> { "Treatment", "Payment", "Operations", "Emergency", "Research" };
        if (!validPurposes.Contains(request.PurposeOfUse))
            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "INVALID_PURPOSE",
                    ErrorMessage = $"Purpose of use must be one of: {string.Join(", ", validPurposes)}",
                    Timestamp = DateTime.UtcNow
                },
                new FaultReason("Invalid purpose of use"));
    }

    private Patient MaskSensitivePatientData(Patient patient, string purposeOfUse)
    {
        // Apply minimum necessary standard per HIPAA
        var maskedPatient = new Patient
        {
            PatientId = patient.PatientId,
            FirstName = patient.FirstName,
            LastName = patient.LastName,
            DateOfBirth = patient.DateOfBirth,
            Gender = patient.Gender,
            Address = patient.Address,
            PhoneNumber = patient.PhoneNumber,
            Email = patient.Email,
            InsuranceDetails = patient.InsuranceDetails
        };

        // Mask SSN for non-payment purposes
        if (purposeOfUse != "Payment" && !string.IsNullOrEmpty(patient.SocialSecurityNumber))
        {
            maskedPatient.SocialSecurityNumber = "***-**-" +
                patient.SocialSecurityNumber.Substring(Math.Max(0, patient.SocialSecurityNumber.Length - 4));
        }
        else
        {
            maskedPatient.SocialSecurityNumber = patient.SocialSecurityNumber;
        }

        // Remove insurance details for research purposes
        if (purposeOfUse == "Research")
        {
            maskedPatient.InsuranceDetails = null;
            maskedPatient.SocialSecurityNumber = null;
            maskedPatient.Address = null;
            maskedPatient.PhoneNumber = null;
            maskedPatient.Email = null;
        }

        return maskedPatient;
    }

    private List<MedicalRecord> FilterRecordsByType(List<MedicalRecord> records, List<string> types)
    {
        var filtered = new List<MedicalRecord>();
        foreach (var record in records)
        {
            var filteredRecord = new MedicalRecord
            {
                RecordId = record.RecordId,
                PatientId = record.PatientId,
                EncounterDate = record.EncounterDate,
                ProviderId = record.ProviderId,
                ProviderName = record.ProviderName,
                FacilityName = record.FacilityName,
                ClinicalNotes = types.Contains("ClinicalNotes") ? record.ClinicalNotes : null,
                Diagnoses = types.Contains("Diagnosis") ? record.Diagnoses : null,
                Procedures = types.Contains("Procedure") ? record.Procedures : null,
                Medications = types.Contains("Medication") ? record.Medications : null,
                LabResults = types.Contains("LabResult") ? record.LabResults : null,
                VitalSigns = types.Contains("VitalSigns") ? record.VitalSigns : null
            };
            filtered.Add(filteredRecord);
        }
        return filtered;
    }

    private AuditInfo CreateAuditEntry(string action, string userId, string organization,
        string purposeOfUse, string patientId)
    {
        return new AuditInfo
        {
            AuditId = Guid.NewGuid().ToString(),
            Timestamp = DateTime.UtcNow,
            Action = action,
            UserId = userId,
            Organization = organization,
            PurposeOfUse = purposeOfUse,
            PatientId = patientId
        };
    }

    private void LogAudit(AuditInfo audit)
    {
        lock (LockObj)
        {
            AuditLog.Add(audit);
        }
        // In production, persist to secure audit database
        Console.WriteLine($"[AUDIT] {audit.Timestamp:O} | {audit.Action} | User: {audit.UserId} | " +
                          $"Org: {audit.Organization} | Patient: {audit.PatientId} | Outcome: {audit.OutcomeCode}");
    }

