// ==================== Custom Security Configuration ====================

public static class HealthcareBindingFactory
{
    /// <summary>
    /// Creates a WS-Security enabled binding with message-level encryption using
    /// mutual X.509 certificates (HIPAA-compliant configuration).
    /// </summary>
    public static CustomBinding CreateHipaaCompliantBinding()
    {
        // Security binding element with mutual certificate authentication
        var security = SecurityBindingElement.CreateMutualCertificateBindingElement(
            MessageSecurityVersion.WSSecurity11WSTrust13WSSecureConversation13WSSecurityPolicy12BasicSecurityProfile10);

        // Configure algorithm suite for strong encryption
        // Uses AES-256 for symmetric encryption, RSA-OAEP for key wrapping, SHA-256 for digest
        security.DefaultAlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;

        // Enable secure session for ongoing communication
        security.IncludeTimestamp = true;
        security.SecurityHeaderLayout = SecurityHeaderLayout.Strict;
        security.MessageProtectionOrder = MessageProtectionOrder.SignBeforeEncryptAndEncryptSignature;

        // Set key derivation
        security.SetKeyDerivation(true);

        // Require signature confirmation
        security.RequireSignatureConfirmation = true;

        // Configure token parameters for encryption
        var protectionTokenParameters = new X509SecurityTokenParameters(
            X509KeyIdentifierClauseType.Thumbprint,
            SecurityTokenInclusionMode.Never);
        security.EndpointSupportingTokenParameters.Endorsing.Add(protectionTokenParameters);

        // Encoding element - MTOM for efficient binary data transfer
        var encoding = new TextMessageEncodingBindingElement(MessageVersion.Soap12WSAddressing10,
            System.Text.Encoding.UTF8);

        // Transport element
        var transport = new HttpsTransportBindingElement
        {
            RequireClientCertificate = true,
            MaxReceivedMessageSize = 10 * 1024 * 1024, // 10MB for medical data
            MaxBufferSize = 10 * 1024 * 1024,
            TransferMode = TransferMode.Buffered
        };

        var binding = new CustomBinding(security, encoding, transport);
        binding.ReceiveTimeout = TimeSpan.FromMinutes(10);
        binding.SendTimeout = TimeSpan.FromMinutes(10);

        return binding;
    }

    /// <summary>
    /// Creates a WSHttpBinding with message security for simpler deployments.
    /// Still uses WS-Security with certificate-based encryption.
    /// </summary>
    public static WSHttpBinding CreateWsHttpSecureBinding()
    {
        var binding = new WSHttpBinding(SecurityMode.TransportWithMessageCredential)
        {
            MaxReceivedMessageSize = 10 * 1024 * 1024,
            ReaderQuotas =
            {
                MaxDepth = 64,
                MaxStringContentLength = 5 * 1024 * 1024,
                MaxArrayLength = 5 * 1024 * 1024,
                MaxBytesPerRead = 1024 * 1024,
                MaxNameTableCharCount = 1024 * 1024
            }
        };

        binding.Security.Transport.ClientCredentialType = HttpClientCredentialType.Certificate;
        binding.Security.Message.ClientCredentialType = MessageCredentialType.Certificate;
        binding.Security.Message.EstablishSecurityContext = true;
        binding.Security.Message.NegotiateServiceCredential = false;
        binding.Security.Message.AlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;

        binding.ReliableSession.Enabled = true;
        binding.ReliableSession.Ordered = true;
        binding.ReliableSession.InactivityTimeout = TimeSpan.FromMinutes(30);

        return binding;
    }

    /// <summary>
    /// Development/testing binding with username/password over transport security.
    /// NOT recommended for production HIPAA environments.
    /// </summary>
    public static WSHttpBinding CreateDevelopmentBinding()
    {
        var binding = new WSHttpBinding(SecurityMode.Message)
        {
            MaxReceivedMessageSize = 10 * 1024 * 1024
        };

        binding.Security.Message.ClientCredentialType = MessageCredentialType.UserName;
        binding.Security.Message.NegotiateServiceCredential = true;
        binding.Security.Message.AlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;

        return binding;
    }
}

// ==================== Service Host Configuration ====================

public class HealthcareServiceHostFactory
{
    private readonly string _baseAddress;
    private readonly string _certSubjectName;
    private readonly StoreLocation _certStoreLocation;

    public HealthcareServiceHostFactory(string baseAddress, string certSubjectName,
        StoreLocation certStoreLocation = StoreLocation.LocalMachine)
    {
        _baseAddress = baseAddress;
        _certSubjectName = certSubjectName;
        _certStoreLocation = certStoreLocation;
    }

    public ServiceHost CreateServiceHost()
    {
        var host = new ServiceHost(typeof(HealthcareRecordsService), new Uri(_baseAddress));

        // Add service endpoint with HIPAA-compliant binding
        var binding = HealthcareBindingFactory.CreateHipaaCompliantBinding();
        var endpoint = host.AddServiceEndpoint(
            typeof(IHealthcareRecordsService),
            binding,
            "HealthcareRecords");

        // Configure service credentials
        ConfigureServiceCredentials(host);

        // Configure service behavior
        ConfigureServiceBehavior(host);

        // Add metadata endpoint (secured)
        ConfigureMetadata(host);

        return host;
    }

    private void ConfigureServiceCredentials(ServiceHost host)
    {
        // Service certificate for encryption and signing
        host.Credentials.ServiceCertificate.SetCertificate(
            _certStoreLocation,
            StoreName.My,
            X509FindType.FindBySubjectName,
            _certSubjectName);

        // Client certificate authentication
        host.Credentials.ClientCertificate.Authentication.CertificateValidationMode =
            System.ServiceModel.Security.X509CertificateValidationMode.ChainTrust;
        host.Credentials.ClientCertificate.Authentication.RevocationMode = X509RevocationMode.Online;

        // Trusted client certificate store
        host.Credentials.ClientCertificate.Authentication.TrustedStoreLocation = _certStoreLocation;

        // Enable audit logging for security events
        var serviceSecurityAudit = host.Description.Behaviors.Find<ServiceSecurityAuditBehavior>();
        if (serviceSecurityAudit == null)
        {
            serviceSecurityAudit = new ServiceSecurityAuditBehavior
            {
                AuditLogLocation = AuditLogLocation.Application,
                SuppressAuditFailure = false,
                ServiceAuthorizationAuditLevel = AuditLevel.SuccessOrFailure,
                MessageAuthenticationAuditLevel = AuditLevel.SuccessOrFailure
            };
            host.Description.Behaviors.Add(serviceSecurityAudit);
        }
    }

    private void ConfigureServiceBehavior(ServiceHost host)
    {
        var behavior = host.Description.Behaviors.Find<ServiceDebugBehavior>();
        if (behavior == null)
        {
            behavior = new ServiceDebugBehavior();
            host.Description.Behaviors.Add(behavior);
        }
        // Never include exception details in production HIPAA environment
        behavior.IncludeExceptionDetailInFaults = false;

        var throttle = host.Description.Behaviors.Find<ServiceThrottlingBehavior>();
        if (throttle == null)
        {
            throttle = new ServiceThrottlingBehavior
            {
                MaxConcurrentCalls = 100,
                MaxConcurrentInstances = 100,
                MaxConcurrentSessions = 100
            };
            host.Description.Behaviors.Add(throttle);
        }
    }

    private void ConfigureMetadata(ServiceHost host)
    {
        var metadataBehavior = host.Description.Behaviors.Find<ServiceMetadataBehavior>();
        if (metadataBehavior == null)
        {
            metadataBehavior = new ServiceMetadataBehavior
            {
                HttpsGetEnabled = true,
                HttpGetEnabled = false // Only HTTPS for metadata in HIPAA
            };
            host.Description.Behaviors.Add(metadataBehavior);
        }
    }
}

