    {
        return Channel.GetLabResults(patientId, fromDate, toDate);
    }

    /// <summary>
    /// Configure client with mutual X.509 certificates for WS-Security.
    /// </summary>
    public void ConfigureCertificates(string clientCertSubject, string serviceCertSubject,
        StoreLocation storeLocation = StoreLocation.LocalMachine)
    {
        // Client certificate for authentication and signing
        ClientCredentials.ClientCertificate.SetCertificate(
            storeLocation,
            StoreName.My,
            X509FindType.FindBySubjectName,
            clientCertSubject);

        // Service certificate for encryption
        ClientCredentials.ServiceCertificate.SetDefaultCertificate(
            storeLocation,
            StoreName.TrustedPeople,
            X509FindType.FindBySubjectName,
            serviceCertSubject);

        // Certificate validation
        ClientCredentials.ServiceCertificate.Authentication.CertificateValidationMode =
            System.ServiceModel.Security.X509CertificateValidationMode.ChainTrust;
        ClientCredentials.ServiceCertificate.Authentication.RevocationMode = X509RevocationMode.Online;
    }
}

// ==================== Key Management Helper ====================

public static class CertificateKeyManager
{
    /// <summary>
    /// Finds a certificate by subject name from the specified store.
    /// </summary>
    public static X509Certificate2 FindCertificate(string subjectName,
        StoreLocation location = StoreLocation.LocalMachine,
        StoreName storeName = StoreName.My)
    {
        using (var store = new X509Store(storeName, location))
        {
            store.Open(OpenFlags.ReadOnly);
            var certs = store.Certificates.Find(
                X509FindType.FindBySubjectName, subjectName, validOnly: true);

            if (certs.Count == 0)
                throw new InvalidOperationException(
                    $"Certificate with subject '{subjectName}' not found in {location}/{storeName}.");

            // Return the most recently issued valid certificate
            X509Certificate2 best = null;
            foreach (X509Certificate2 cert in certs)
            {
                if (cert.HasPrivateKey && (best == null || cert.NotBefore > best.NotBefore))
                    best = cert;
            }

            return best ?? certs[0];
        }
    }

    /// <summary>
    /// Validates that a certificate meets HIPAA minimum requirements.
    /// </summary>
    public static bool ValidateCertificateForHipaa(X509Certificate2 cert)
    {
        if (cert == null) return false;

        // Check key size (minimum 2048-bit RSA)
        if (cert.PublicKey.Key.KeySize < 2048)
        {
            Console.WriteLine($"Certificate key size {cert.PublicKey.Key.KeySize} is below minimum 2048-bit requirement.");
            return false;
        }

        // Check expiration
        if (cert.NotAfter < DateTime.UtcNow)
        {
            Console.WriteLine("Certificate has expired.");
            return false;
        }

        // Check that it's not expiring within 30 days
        if (cert.NotAfter < DateTime.UtcNow.AddDays(30))
        {
            Console.WriteLine("WARNING: Certificate expires within 30 days.");
        }

        // Check signature algorithm (should not be SHA-1)
        if (cert.SignatureAlgorithm.FriendlyName.Contains("sha1"))
        {
            Console.WriteLine("Certificate uses SHA-1 which is not recommended for HIPAA compliance.");
            return false;
        }

        return true;
    }

    /// <summary>
    /// Gets information about the encryption algorithms used.
    /// </summary>
    public static void PrintAlgorithmSuiteInfo(SecurityAlgorithmSuite suite)
    {
        Console.WriteLine("=== HIPAA Encryption Configuration ===");
        Console.WriteLine($"Algorithm Suite: {suite.GetType().Name}");
        Console.WriteLine($"Default Symmetric Key Length: {suite.DefaultSymmetricKeyLength} bits");
        Console.WriteLine($"Default Encryption Algorithm: {suite.DefaultEncryptionAlgorithm}");
        Console.WriteLine($"Default Symmetric Signature Algorithm: {suite.DefaultSymmetricSignatureAlgorithm}");
        Console.WriteLine($"Default Asymmetric Signature Algorithm: {suite.DefaultAsymmetricSignatureAlgorithm}");
        Console.WriteLine($"Default Digest Algorithm: {suite.DefaultDigestAlgorithm}");
        Console.WriteLine($"Default Asymmetric Key Wrap Algorithm: {suite.DefaultAsymmetricKeyWrapAlgorithm}");
        Console.WriteLine("========================================");
    }
}

